+        .lambda => |lam| isParameterCalledInExpr(lam.body.*, param_name),
+        .binop => |binop| {
+            return isParameterCalledInExpr(binop.left.*, param_name) or
+                isParameterCalledInExpr(binop.right.*, param_name);
